#include <bits/stdc++.h>
using namespace std;

const int mod = int(1e9) + 7;
int n, m;
int a, b;
int f[200005];
int l[200005], r[200005];

int find(int x) {
    if (f[x] != x) {
        f[x] = find(f[x]);
    }
    return f[x];
}

void add(int x, int y) {
    x = find(x);
    y = find(y);
    f[x] = y;
}

int main() {
    cin >> n >> m;
    for (int i = 1; i <= n; i++) f[i] = i;
    for (int i = 0; i < m; i++) {
        cin >> a >> b;
        if (l[b] == a && r[a] == b) continue;
        if (l[b] || r[a] || find(a) == find(b)) {
            cout << 0;
            return 0;
        }
        add(a, b);
        l[b] = a;
        r[a] = b;
    }
    int cnt = 0;
    for (int i = 1; i <= n; i++) {
        if (f[i] == i) cnt++;
    }
    long long ans = 1;
    for (int i = 2; i <= cnt; i++) {
        ans = ans * i % mod;
    }
    cout << ans;
    return 0;
}
